/**
 * Twitter Feed System Design — Key Architecture Points
 *
 * Requirement: 300M users, 500M tweets/day, P99 feed load < 100ms
 *
 * APPROACH 1: Pull (Fan-out on Read) — DOESN'T SCALE
 * ─────────────────────────────────────────────────────
 * On feed request:
 *   SELECT t.* FROM tweets t
 *   JOIN follows f ON t.user_id = f.followed_id
 *   WHERE f.follower_id = :userId
 *   ORDER BY created_at DESC LIMIT 20
 *
 * Problem: user follows 500 people → scan 500 × (avg 10 tweets/day)
 * = 5000 rows per request, JOIN on hot table, no cache hit rate
 * Unacceptable for 300M daily active users.
 *
 * APPROACH 2: Push (Fan-out on Write) — CELEBRITY PROBLEM
 * ─────────────────────────────────────────────────────────
 * On tweet creation:
 *   for each follower of tweeter:
 *       ZADD timeline:{followerId} score={timestamp} member={tweetId}
 *
 * Normal user (200 followers): 200 Redis writes — fast, fine.
 * Celebrity (50M followers):   50M Redis writes — thundering herd!
 * Barack Obama tweets → 50M ZADD ops → Redis overwhelmed.
 *
 * APPROACH 3: Hybrid — TWITTER'S ACTUAL SOLUTION
 * ─────────────────────────────────────────────────
 */

// Pseudo-code for hybrid fan-out service:
public class FanOutService {
    // Users with > CELEBRITY_THRESHOLD followers use pull model
    private static final int CELEBRITY_THRESHOLD = 100_000;

    public void onNewTweet(long tweetId, long authorId) {
        List<Long> followers = followRepo.getFollowers(authorId);
        boolean isCelebrity = followers.size() > CELEBRITY_THRESHOLD;

        if (!isCelebrity) {
            // Fan-out on write: push to all follower timelines
            for (long followerId : followers) {
                redis.zadd("timeline:" + followerId,
                           System.currentTimeMillis(), tweetId);
            }
        }
        // Celebrity tweets are NOT fanned out — they're pulled at read time
    }

    public List<Long> getTimeline(long userId) {
        // Step 1: get precomputed timeline (normal users)
        List<Long> tweetIds = redis.zrange("timeline:" + userId, 0, 19, true);

        // Step 2: merge in celebrity tweets (pulled on demand)
        List<Long> celebFollowing = getFollowedCelebrities(userId);
        for (long celebId : celebFollowing) {
            List<Long> celebTweets = redis.zrange("user_tweets:" + celebId, 0, 4, true);
            tweetIds.addAll(celebTweets);
        }

        // Step 3: sort merged results by timestamp, take top 20
        return tweetIds.stream()
            .sorted(Comparator.reverseOrder()) // sorted set score = timestamp
            .limit(20)
            .collect(toList());
    }
}

/**
 * DATA FLOW SUMMARY:
 *
 * Write path: Tweet → Kafka topic → Fan-out consumers → Redis ZADD (per follower)
 * Read path:  GET /timeline → Redis ZRANGE (O(log N)) → hydrate tweet data from cache/DB
 *
 * Scale numbers:
 * - 500M tweets/day = ~6000 tweets/sec
 * - Avg 200 followers = 1.2M Redis writes/sec (manageable)
 * - 300M DAU × 20 feed loads/day = 6B reads/day = ~70K reads/sec
 * - Redis handles ~1M ops/sec → need ~70 Redis shards for reads
 */

