import java.util.*;

public class Q3 {
    static final Map<String, Integer> ORDER = Map.of("SENT", 1, "DELIVERED", 2, "READ", 3);
    static final String[] NAMES = {"", "SENT", "DELIVERED", "READ"};

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt(); sc.nextLine();
        Map<String, Integer> states = new TreeMap<>();
        for (int i = 0; i < n; i++) {
            String[] parts = sc.nextLine().trim().split(" ");
            String msgId = parts[0], event = parts[1];
            int newState = ORDER.get(event);
            int cur = states.getOrDefault(msgId, 0);
            if (newState > cur) states.put(msgId, newState);
        }
        states.forEach((k, v) -> System.out.println(k + ": " + NAMES[v]));
    }
}
